import{_ as a,c as i,o as r,ag as l}from"./chunks/framework.piE7uVCg.js";const n="/assets/evac1.C3NV37AB.jpg",h=JSON.parse(`{"title":"Plan d'évacuation","description":"","frontmatter":{},"headers":[],"relativePath":"securite/incendie/normes/evac.md","filePath":"securite/incendie/normes/evac.md"}`),t={name:"securite/incendie/normes/evac.md"};function s(u,e,o,c,d,p){return r(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="plan-d-evacuation" tabindex="-1"><a href="./readme.html">Plan d&#39;évacuation</a> <a class="header-anchor" href="#plan-d-evacuation" aria-label="Permalink to &quot;[Plan d&#39;évacuation](readme.md)&quot;">​</a></h1><h2 id="plan" tabindex="-1">Plan <a class="header-anchor" href="#plan" aria-label="Permalink to &quot;Plan&quot;">​</a></h2><p><img src="'+n+'" alt="plan"></p><h3 id="regles-pratiques" tabindex="-1">Règles pratiques <a class="header-anchor" href="#regles-pratiques" aria-label="Permalink to &quot;Règles pratiques&quot;">​</a></h3><ul><li>À chaque étage : au moins un plan d’évacuation par niveau.</li><li>À chaque issue de secours ou escalier : placer un plan avant d’y accéder.</li><li>Dans les zones à forte fréquentation : un plan visible tous les 15 à 20 m de parcours.</li><li>Pour les bâtiments complexes (hôtels, bureaux, centres commerciaux) : prévoir un plan par zone afin qu’il soit toujours visible depuis un point de passage.</li></ul><h3 id="caracteriqtiques-du-plan" tabindex="-1">Caractériqtiques du plan <a class="header-anchor" href="#caracteriqtiques-du-plan" aria-label="Permalink to &quot;Caractériqtiques du plan&quot;">​</a></h3><ul><li>Placé à hauteur des yeux (~1,50 m).</li><li>Résistant au feu et aux dégradations.</li><li>Inclure : <ul><li>Vous êtes ici ✅</li><li>Chemins d’évacuation et issues.</li><li>Points de rassemblement.</li><li>Moyens de lutte contre l’incendie (extincteurs, alarmes)</li></ul></li></ul><h3 id="bonnes-pratiques" tabindex="-1">Bonnes pratiques <a class="header-anchor" href="#bonnes-pratiques" aria-label="Permalink to &quot;Bonnes pratiques&quot;">​</a></h3><ul><li>Faire des excercices réguliers</li><li>Former régulièrement le personnel ou les occupants.</li><li>Organiser au moins un exercice d’évacuation par an.</li><li>Mettre à jour les consignes à chaque modification du bâtiment ou des procédures.</li><li>Vérifier la visibilité (pas derrière un meuble ou une porte).</li></ul>',9)])])}const q=a(t,[["render",s]]);export{h as __pageData,q as default};
